diagrams.content:
classDiagram
    class Benutzer {
        +String telefonnummer
        +boolean verifiziert
        +registrieren()
        +verifizieren()
    }

    class Registrierung {
        +String code
        +sendCode()
        +validateCode()
    }

    Benutzer "1" -- "1" Registrierung : registriert

%%{init: {'theme': 'default'}}%%
graph TD
    A[Benutzer] -->|Registrierung| B(Telefonnummer-Registrierung)
    B -->|Verifizierung| C[Verifizierungsdienst]
    B -->|Daten speichern| D[Datenbank]
    A -->|Benachrichtigung| E[Benachrichtigungsdienst]

    style A fill:#f9f,stroke:#333,stroke-width:2px;
    style B fill:#bbf,stroke:#333,stroke-width:2px;
    style C fill:#bbf,stroke:#333,stroke-width:2px;
    style D fill:#bbf,stroke:#333,stroke-width:2px;
    style E fill:#bbf,stroke:#333,stroke-width:2px;

